Build an API client where the return type automatically changes based on the endpoint string passed in.

```typescript
// API endpoint → response type mapping
interface ApiEndpoints {
  '/users': User[];
  '/users/:id': User;
  '/posts': Post[];
  '/posts/:id': Post;
  '/health': { status: 'ok'; uptime: number };
}

interface User { id: string; name: string; email: string }
interface Post { id: string; title: string; body: string }

// Type-safe fetch wrapper
async function api<E extends keyof ApiEndpoints>(
  endpoint: E,
  init?: RequestInit
): Promise<ApiEndpoints[E]> {
  const response = await fetch(`/api${endpoint}`, init);
  if (!response.ok) throw new Error(`HTTP ${response.status}`);
  return response.json();
}

// Usage — return type inferred from endpoint
const users = await api('/users');      // User[]
const user = await api('/users/:id');   // User
const health = await api('/health');    // { status: 'ok'; uptime: number }
const invalid = await api('/nope');     // Error: '/nope' not in ApiEndpoints

// Extend for methods
interface ApiMethods {
  GET: ApiEndpoints;
  POST: {
    '/users': User;
    '/posts': Post;
  };
}

async function apiMethod<
  M extends keyof ApiMethods,
  E extends keyof ApiMethods[M] & string
>(method: M, endpoint: E, body?: unknown): Promise<ApiMethods[M][E]> {
  return fetch(`/api${endpoint}`, {
    method,
    body: body ? JSON.stringify(body) : undefined,
  }).then(r => r.json());
}

const newUser = await apiMethod('POST', '/users', { name: 'Alice' }); // User
```

Map endpoints to response types in an interface, then use that interface as a generic constraint. The compiler resolves the return type automatically.

Define recursive types for tree structures, nested JSON, and deeply nested configurations.

```typescript
// JSON type
type Json = string | number | boolean | null | Json[] | { [key: string]: Json };

// Parse unknown to typed JSON
function parseJson(raw: unknown): Json {
  if (raw === null || typeof raw === 'string' || typeof raw === 'number' || typeof raw === 'boolean') {
    return raw;
  }
  if (Array.isArray(raw)) return raw.map(parseJson);
  if (typeof raw === 'object') {
    return Object.fromEntries(
      Object.entries(raw as Record<string, unknown>).map(([k, v]) => [k, parseJson(v)])
    );
  }
  throw new Error(`Cannot convert ${typeof raw} to JSON`);
}

// Tree node type
interface TreeNode<T> {
  value: T;
  children: TreeNode<T>[];
}

// Recursive tree operations
function findInTree<T>(node: TreeNode<T>, predicate: (value: T) => boolean): T | undefined {
  if (predicate(node.value)) return node.value;
  for (const child of node.children) {
    const found = findInTree(child, predicate);
    if (found !== undefined) return found;
  }
  return undefined;
}

function mapTree<T, U>(node: TreeNode<T>, fn: (value: T) => U): TreeNode<U> {
  return {
    value: fn(node.value),
    children: node.children.map(child => mapTree(child, fn)),
  };
}

// Deeply nested path type (limited depth to avoid infinite recursion)
type DeepPath<T, D extends number = 5> = D extends 0 ? never :
  T extends object ? {
    [K in keyof T & string]: K | `${K}.${DeepPath<T[K], Prev[D]>}`
  }[keyof T & string] : never;
type Prev = [never, 0, 1, 2, 3, 4];
```

Limit recursive type depth to avoid `Type instantiation is excessively deep` errors. TypeScript caps recursive types at around 50 levels.

