Combine TypeScript utility types to express complex domain requirements without verbose type definitions.

```typescript
interface User {
  id: string;
  name: string;
  email: string;
  passwordHash: string;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
}

// Public user (omit sensitive fields)
type PublicUser = Omit<User, 'passwordHash' | 'deletedAt'>;

// Create input (omit auto-generated fields)
type CreateUser = Omit<User, 'id' | 'createdAt' | 'updatedAt' | 'deletedAt'>;

// Update input (partial of editable fields only)
type UpdateUser = Partial<Pick<User, 'name' | 'email'>>;

// Make specific fields required
type RequiredFields<T, K extends keyof T> = T & Required<Pick<T, K>>;
type UserWithAvatar = RequiredFields<Partial<User>, 'id' | 'name'>;

// Make specific fields optional
type OptionalFields<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
type FlexibleUser = OptionalFields<User, 'email' | 'passwordHash'>;

// NonNullable on specific fields
type WithNonNull<T, K extends keyof T> = T & { [P in K]: NonNullable<T[P]> };
type ActiveUser = WithNonNull<User, 'deletedAt'>;
// deletedAt is Date (not null)

// Combine: pick + transform
type UserSummary = Pick<User, 'id' | 'name'> & {
  displayName: string;
  isActive: boolean;
};
```

Layer utility types like `Pick`, `Omit`, `Partial`, `Required`, and `NonNullable` to derive precise types from base interfaces. This avoids type duplication and keeps types in sync.

Create type-safe action creators for Redux-style patterns using discriminated unions with automatic type inference.

```typescript
// Action type map
interface ActionMap {
  'todos/add': { text: string };
  'todos/toggle': { id: string };
  'todos/remove': { id: string };
  'filter/set': { filter: 'all' | 'active' | 'completed' };
  'app/reset': undefined;
}

// Generate discriminated union from map
type Action = {
  [K in keyof ActionMap]: ActionMap[K] extends undefined
    ? { type: K }
    : { type: K; payload: ActionMap[K] }
}[keyof ActionMap];

// Action creator factory
function createAction<K extends keyof ActionMap>(
  type: K,
  ...args: ActionMap[K] extends undefined ? [] : [payload: ActionMap[K]]
): Extract<Action, { type: K }> {
  return (args.length > 0 ? { type, payload: args[0] } : { type }) as any;
}

// Usage — fully typed, auto-completed
const add = createAction('todos/add', { text: 'Buy milk' });
const toggle = createAction('todos/toggle', { id: '1' });
const reset = createAction('app/reset'); // No payload needed

// Error cases:
createAction('todos/add'); // Error: Expected 2 arguments
createAction('todos/add', { wrong: true }); // Error: 'wrong' doesn't exist
createAction('app/reset', {}); // Error: Expected 1 argument

// Type-safe reducer
function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'todos/add':
      return { ...state, todos: [...state.todos, { id: crypto.randomUUID(), text: action.payload.text }] };
    case 'todos/toggle':
      return { ...state, todos: state.todos.map(t => t.id === action.payload.id ? { ...t, done: !t.done } : t) };
    default:
      return state;
  }
}
```

The `ActionMap` interface is the single source of truth. Adding a new action type automatically creates the creator signature and the union member.

Build a middleware chain where each middleware can augment the context type, and the final handler sees the accumulated context.

```typescript
// Base context
interface BaseContext {
  req: Request;
  res: Response;
}

// Middleware type — takes context and returns augmented context
type Middleware<In, Out> = (ctx: In) => Out | Promise<Out>;

// Chain builder
class MiddlewareChain<Ctx extends BaseContext> {
  private middlewares: Function[] = [];

  use<NewCtx extends Ctx>(
    middleware: Middleware<Ctx, NewCtx>
  ): MiddlewareChain<NewCtx> {
    this.middlewares.push(middleware);
    return this as unknown as MiddlewareChain<NewCtx>;
  }

  handle(handler: (ctx: Ctx) => void | Promise<void>): (req: Request, res: Response) => Promise<void> {
    return async (req, res) => {
      let ctx: any = { req, res };
      for (const mw of this.middlewares) {
        ctx = await mw(ctx);
      }
      await handler(ctx);
    };
  }
}

// Middlewares that augment context
const withAuth: Middleware<BaseContext, BaseContext & { user: { id: string; role: string } }> = (ctx) => {
  return { ...ctx, user: { id: '123', role: 'admin' } };
};

const withDb: Middleware<BaseContext, BaseContext & { db: { query: (sql: string) => Promise<unknown[]> } }> = (ctx) => {
  return { ...ctx, db: { query: async (sql) => [] } };
};

// Usage
const app = new MiddlewareChain()
  .use(withAuth)
  .use(withDb)
  .handle(async (ctx) => {
    ctx.user.id;        // string ✓
    ctx.user.role;      // string ✓
    ctx.db.query('..'); // ✓
    ctx.req;            // Request ✓
  });
```

Use `as const` objects with derived types as a fully type-safe, tree-shakeable alternative to TypeScript enums.

```typescript
// Define the enum-like object
const HttpStatus = {
  OK: 200,
  Created: 201,
  BadRequest: 400,
  Unauthorized: 401,
  NotFound: 404,
  InternalError: 500,
} as const;

// Derive the union type from values
type HttpStatus = typeof HttpStatus[keyof typeof HttpStatus];
// 200 | 201 | 400 | 401 | 404 | 500

// Derive key type
type HttpStatusName = keyof typeof HttpStatus;
// 'OK' | 'Created' | 'BadRequest' | 'Unauthorized' | 'NotFound' | 'InternalError'

// Use in functions
function getStatusText(status: HttpStatus): string {
  switch (status) {
    case HttpStatus.OK: return 'OK';
    case HttpStatus.NotFound: return 'Not Found';
    default: return 'Unknown';
  }
}

// Reverse lookup
const statusByCode = Object.fromEntries(
  Object.entries(HttpStatus).map(([k, v]) => [v, k])
) as Record<HttpStatus, HttpStatusName>;

console.log(statusByCode[200]); // 'OK'

// Advantages over enum:
// ✓ No reverse mapping confusion
// ✓ Works with isolatedModules (Vite, esbuild)
// ✓ Tree-shakeable — unused values are removed
// ✓ Standard JavaScript — no TS-specific emit
// ✓ Values are actual literals, not opaque numbers
```

This is the recommended pattern for most TypeScript projects. Enums are only necessary when you specifically need nominal typing.

Use mapped types to automatically generate a typed SDK from a route definition object.

```typescript
// Route definitions
interface Routes {
  'GET /users': { response: User[]; query: { page?: number; limit?: number } };
  'GET /users/:id': { response: User; params: { id: string } };
  'POST /users': { response: User; body: CreateUserDto };
  'PUT /users/:id': { response: User; params: { id: string }; body: UpdateUserDto };
  'DELETE /users/:id': { response: void; params: { id: string } };
}

// Extract method and path from route key
type Method<R extends string> = R extends `${infer M} ${string}` ? M : never;
type Path<R extends string> = R extends `${string} ${infer P}` ? P : never;

// Build SDK type automatically
type SDK = {
  [R in keyof Routes as `${Lowercase<Method<R & string>>}${Capitalize<Path<R & string>>}`]:
    Routes[R] extends { params: infer P; body: infer B }
      ? (params: P, body: B) => Promise<Routes[R]['response']>
      : Routes[R] extends { params: infer P }
        ? (params: P) => Promise<Routes[R]['response']>
        : Routes[R] extends { body: infer B }
          ? (body: B) => Promise<Routes[R]['response']>
          : Routes[R] extends { query: infer Q }
            ? (query?: Q) => Promise<Routes[R]['response']>
            : () => Promise<Routes[R]['response']>;
};

// The SDK type now has methods like:
// get/users: (query?: { page?: number; limit?: number }) => Promise<User[]>
// post/users: (body: CreateUserDto) => Promise<User>
// etc.
```

Mapped types with template literal keys can generate entire API surfaces from declarative definitions. This pattern is the basis for typed RPC frameworks.

