Use JavaScript Proxy with TypeScript types to create objects that validate types at both compile time and runtime.

```typescript
function createTypedProxy<T extends Record<string, unknown>>(
  target: T,
  validators: { [K in keyof T]?: (value: unknown) => value is T[K] }
): T {
  return new Proxy(target, {
    set(obj, prop, value) {
      const key = prop as keyof T;
      const validator = validators[key];
      if (validator && !validator(value)) {
        throw new TypeError(
          `Invalid value for '${String(prop)}': expected ${typeof obj[key]}, got ${typeof value}`
        );
      }
      return Reflect.set(obj, prop, value);
    },
    get(obj, prop) {
      return Reflect.get(obj, prop);
    },
  });
}

// Define validators
const isString = (v: unknown): v is string => typeof v === 'string';
const isNumber = (v: unknown): v is number => typeof v === 'number';

// Usage
const config = createTypedProxy(
  { host: 'localhost', port: 3000, debug: false },
  { host: isString, port: isNumber }
);

config.host = 'example.com'; // OK at compile time and runtime
config.port = '8080' as any; // Compile: OK with any, Runtime: TypeError!
config.port = 8080;          // OK at both levels
```

This provides a double safety net: TypeScript catches type errors at compile time, and the Proxy catches errors from `any`, type assertions, or external input at runtime.

A type-safe retry utility that preserves the return type of the retried function.

```typescript
interface RetryOptions {
  maxRetries: number;
  baseDelay: number;
  maxDelay?: number;
  shouldRetry?: (error: unknown, attempt: number) => boolean;
  onRetry?: (error: unknown, attempt: number) => void;
}

async function retry<T>(
  fn: () => Promise<T>,
  options: RetryOptions
): Promise<T> {
  const { maxRetries, baseDelay, maxDelay = 30000, shouldRetry, onRetry } = options;

  let lastError: unknown;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      if (attempt === maxRetries) break;
      if (shouldRetry && !shouldRetry(error, attempt)) break;

      onRetry?.(error, attempt);

      const delay = Math.min(
        baseDelay * Math.pow(2, attempt) + Math.random() * 100,
        maxDelay
      );
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
  throw lastError;
}

// Usage
const data = await retry(
  () => fetch('https://api.example.com/data').then(r => {
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    return r.json() as Promise<{ items: string[] }>;
  }),
  {
    maxRetries: 3,
    baseDelay: 1000,
    shouldRetry: (err) => {
      if (err instanceof Error && err.message.includes('HTTP 4')) return false;
      return true; // Retry server errors and network failures
    },
    onRetry: (err, attempt) => console.log(`Retry ${attempt + 1}:`, err),
  }
);
// data is { items: string[] } — type preserved
```

A deeply-typed merge function that correctly handles nested objects, arrays, and preserves type information.

```typescript
type DeepMerge<T, U> = {
  [K in keyof T | keyof U]: K extends keyof U
    ? K extends keyof T
      ? T[K] extends object
        ? U[K] extends object
          ? DeepMerge<T[K], U[K]>
          : U[K]
        : U[K]
      : U[K]
    : K extends keyof T
      ? T[K]
      : never;
};

function deepMerge<T extends Record<string, any>, U extends Record<string, any>>(
  target: T,
  source: U
): DeepMerge<T, U> {
  const result = { ...target } as any;

  for (const key of Object.keys(source)) {
    const targetVal = target[key];
    const sourceVal = source[key];

    if (
      sourceVal !== null &&
      typeof sourceVal === 'object' &&
      !Array.isArray(sourceVal) &&
      targetVal !== null &&
      typeof targetVal === 'object' &&
      !Array.isArray(targetVal)
    ) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

// Usage
const defaults = {
  server: { host: 'localhost', port: 3000 },
  logging: { level: 'info' as const, pretty: false },
};

const overrides = {
  server: { port: 8080 },
  logging: { pretty: true },
};

const config = deepMerge(defaults, overrides);
// Type: { server: { host: string; port: number }; logging: { level: 'info'; pretty: boolean } }
// Value: { server: { host: 'localhost', port: 8080 }, logging: { level: 'info', pretty: true } }
```

