class TypedStorage {
  get<K extends keyof StorageSchema>(key: K): StorageSchema[K] | null {
    const raw = localStorage.getItem(key as string);
    if (raw === null) return null;
    try {
      return JSON.parse(raw) as StorageSchema[K];
    } catch {
      return raw as StorageSchema[K];
    }
  }

  set<K extends keyof StorageSchema>(key: K, value: StorageSchema[K]): void {
    localStorage.setItem(key as string, JSON.stringify(value));
  }

  remove<K extends keyof StorageSchema>(key: K): void {
    localStorage.removeItem(key as string);
  }

  getOrDefault<K extends keyof StorageSchema>(
    key: K,
    defaultValue: StorageSchema[K]
  ): StorageSchema[K] {
    return this.get(key) ?? defaultValue;
  }
}

export const storage = new TypedStorage();

// Usage — fully typed!
storage.set('theme', 'dark');                    // OK
storage.set('theme', 'blue');                    // Error: 'blue' not assignable
storage.set('cart', [{ id: '1', quantity: 2 }]); // OK
storage.set('cart', [{ id: '1' }]);              // Error: missing 'quantity'

const theme = storage.get('theme'); // 'light' | 'dark' | null
const cart = storage.getOrDefault('cart', []); // Array<{ id: string; quantity: number }>
```

A `pipe` utility that chains functions with correct type inference through the entire pipeline.

```typescript
// Overloaded pipe for up to 6 functions
function pipe<A>(value: A): A;
function pipe<A, B>(value: A, fn1: (a: A) => B): B;
function pipe<A, B, C>(value: A, fn1: (a: A) => B, fn2: (b: B) => C): C;
function pipe<A, B, C, D>(value: A, fn1: (a: A) => B, fn2: (b: B) => C, fn3: (c: C) => D): D;
function pipe<A, B, C, D, E>(value: A, fn1: (a: A) => B, fn2: (b: B) => C, fn3: (c: C) => D, fn4: (d: D) => E): E;
function pipe(value: unknown, ...fns: Function[]): unknown {
  return fns.reduce((acc, fn) => fn(acc), value);
}

// Usage — types flow through each step
const result = pipe(
  ' Hello, World! ',
  (s: string) => s.trim(),           // string
  (s) => s.toLowerCase(),             // string (inferred)
  (s) => s.split(', '),              // string[]
  (arr) => arr.map(w => w.length),   // number[]
  (nums) => nums.reduce((a, b) => a + b, 0) // number
);
// result: number = 17

// Async pipe
async function pipeAsync<A>(value: A, ...fns: ((arg: any) => any)[]): Promise<any> {
  let result: any = value;
  for (const fn of fns) {
    result = await fn(result);
  }
  return result;
}

const user = await pipeAsync(
  userId,
  (id: string) => fetch(`/api/users/${id}`),
  (res: Response) => res.json(),
  (data: any) => data as User
);
```

The overloaded signatures ensure each function receives the output type of the previous function. Add more overloads for longer pipelines.

A fetch wrapper that validates responses at runtime with Zod and provides compile-time type safety.

```typescript
import { z, ZodSchema } from 'zod';

class ApiError extends Error {
  constructor(
    public status: number,
    public statusText: string,
    public body: unknown
  ) {
    super(`API Error: ${status} ${statusText}`);
    this.name = 'ApiError';
  }
}

async function typedFetch<T>(
  url: string,
  schema: ZodSchema<T>,
  init?: RequestInit
): Promise<T> {
  const response = await fetch(url, {
    ...init,
    headers: {
      'Content-Type': 'application/json',
      ...init?.headers,
    },
  });

  if (!response.ok) {
    const body = await response.text().catch(() => 'No body');
    throw new ApiError(response.status, response.statusText, body);
  }

  const json = await response.json();
  const result = schema.safeParse(json);

  if (!result.success) {
    console.error('Response validation failed:', result.error.issues);
    throw new Error(`Invalid response from ${url}: ${result.error.message}`);
  }

  return result.data;
}

// Usage
const userSchema = z.object({
  id: z.string(),
  name: z.string(),
  email: z.string().email(),
});

const user = await typedFetch('/api/users/1', userSchema);
// user: { id: string; name: string; email: string } — validated at runtime!

const usersSchema = z.array(userSchema);
const users = await typedFetch('/api/users', usersSchema);
// users: { id: string; name: string; email: string }[] — validated!
```

A `match` function that provides exhaustive pattern matching on discriminated unions, similar to Rust's `match` or ML pattern matching.

```typescript
type Match<T extends { type: string }, R> = {
  [K in T['type']]: (value: Extract<T, { type: K }>) => R;
};

function match<T extends { type: string }, R>(
  value: T,
  handlers: Match<T, R>
): R {
  const handler = handlers[value.type as keyof typeof handlers];
  return (handler as any)(value);
}

// Usage with events
type AppEvent =
  | { type: 'click'; x: number; y: number }
  | { type: 'keypress'; key: string; ctrl: boolean }
  | { type: 'scroll'; delta: number }
  | { type: 'resize'; width: number; height: number };

function handleEvent(event: AppEvent): string {
  return match(event, {
    click: ({ x, y }) => `Clicked at (${x}, ${y})`,
    keypress: ({ key, ctrl }) => `${ctrl ? 'Ctrl+' : ''}${key}`,
    scroll: ({ delta }) => `Scrolled ${delta}px`,
    resize: ({ width, height }) => `Resized to ${width}x${height}`,
  });
}

// If you add a new event type, you get a compile error:
// type AppEvent = ... | { type: 'focus'; target: string };
// Error: Property 'focus' is missing in type '{ click: ...; keypress: ...; scroll: ...; resize: ...; }'

// Works with any discriminant key:
type Shape = { kind: 'circle'; r: number } | { kind: 'rect'; w: number; h: number };
type MatchByKind<T extends { kind: string }, R> = {
  [K in T['kind']]: (value: Extract<T, { kind: K }>) => R;
};
```

This is more ergonomic than switch statements and guarantees exhaustiveness at compile time.

An advanced event bus with typed events, wildcard listeners, and one-time subscription support.

```typescript
type EventMap = Record<string, unknown>;
type WildcardHandler<E extends EventMap> = (type: keyof E, payload: E[keyof E]) => void;

class EventBus<E extends EventMap> {
  private handlers = new Map<keyof E | '*', Set<Function>>();
  private onceHandlers = new WeakSet<Function>();

  on<K extends keyof E>(event: K, handler: (payload: E[K]) => void): () => void {
    return this.addHandler(event, handler);
  }

  once<K extends keyof E>(event: K, handler: (payload: E[K]) => void): () => void {
    this.onceHandlers.add(handler);
    return this.addHandler(event, handler);
  }

  onAny(handler: WildcardHandler<E>): () => void {
    return this.addHandler('*' as any, handler);
  }

  emit<K extends keyof E>(event: K, payload: E[K]): void {
    // Specific handlers
    this.handlers.get(event)?.forEach(handler => {
      handler(payload);
      if (this.onceHandlers.has(handler)) {
        this.handlers.get(event)?.delete(handler);
        this.onceHandlers.delete(handler);
      }
    });
    // Wildcard handlers
    this.handlers.get('*' as any)?.forEach(handler => handler(event, payload));
  }

  private addHandler(event: keyof E | '*', handler: Function): () => void {
    if (!this.handlers.has(event)) this.handlers.set(event, new Set());
    this.handlers.get(event)!.add(handler);
    return () => {
      this.handlers.get(event)?.delete(handler);
      this.onceHandlers.delete(handler);
    };
  }
}

// Usage
interface Events {
  'message': { from: string; text: string };
  'status': 'online' | 'offline';
  'typing': { userId: string };
}

const bus = new EventBus<Events>();

bus.on('message', (msg) => console.log(`${msg.from}: ${msg.text}`));
bus.once('status', (s) => console.log(`First status: ${s}`));
bus.onAny((type, payload) => console.log(`[${String(type)}]`, payload));

bus.emit('message', { from: 'Alice', text: 'Hello' });
bus.emit('status', 'online'); // Fires once handler, then removes it
```

Build and parse URL query strings with full type safety from a schema definition.

```typescript
// Schema defines allowed query params and their types
interface SearchParams {
  q: string;
  page: number;
  limit: number;
  sort: 'asc' | 'desc';
  tags: string[];
  featured: boolean;
}

// Builder
function buildQuery<T extends Record<string, string | number | boolean | string[]>>(
  params: Partial<T>
): string {
  const searchParams = new URLSearchParams();
  for (const [key, value] of Object.entries(params)) {
    if (value === undefined || value === null) continue;
    if (Array.isArray(value)) {
      value.forEach(v => searchParams.append(key, String(v)));
    } else {
      searchParams.set(key, String(value));
    }
  }
  return searchParams.toString();
}

// Parser with type coercion
function parseQuery<T extends Record<string, string | number | boolean | string[]>>(
  search: string,
  schema: { [K in keyof T]: 'string' | 'number' | 'boolean' | 'string[]' }
): Partial<T> {
  const params = new URLSearchParams(search);
  const result: any = {};
  for (const [key, type] of Object.entries(schema)) {
    if (!params.has(key)) continue;
    switch (type) {
      case 'number': result[key] = Number(params.get(key)); break;
      case 'boolean': result[key] = params.get(key) === 'true'; break;
      case 'string[]': result[key] = params.getAll(key); break;
      default: result[key] = params.get(key);
    }
  }
  return result;
}

// Usage
const qs = buildQuery<SearchParams>({
  q: 'typescript',
  page: 1,
  sort: 'desc',
  tags: ['tutorial', 'advanced'],
});
// 'q=typescript&page=1&sort=desc&tags=tutorial&tags=advanced'

const parsed = parseQuery<SearchParams>(qs, {
  q: 'string', page: 'number', limit: 'number',
  sort: 'string', tags: 'string[]', featured: 'boolean',
});
// parsed.page is number, parsed.tags is string[]
```

Debounce and throttle functions that preserve the original function's type signature.

```typescript
function debounce<T extends (...args: any[]) => any>(
  fn: T,
  delay: number
): (...args: Parameters<T>) => void {
  let timeoutId: ReturnType<typeof setTimeout>;
  return function (this: any, ...args: Parameters<T>) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), delay);
  };
}

function throttle<T extends (...args: any[]) => any>(
  fn: T,
  interval: number
): (...args: Parameters<T>) => void {
  let lastTime = 0;
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  return function (this: any, ...args: Parameters<T>) {
    const now = Date.now();
    const remaining = interval - (now - lastTime);

    if (remaining <= 0) {
      if (timeoutId) { clearTimeout(timeoutId); timeoutId = null; }
      lastTime = now;
      fn.apply(this, args);
    } else if (!timeoutId) {
      timeoutId = setTimeout(() => {
        lastTime = Date.now();
        timeoutId = null;
        fn.apply(this, args);
      }, remaining);
    }
  };
}

// Usage — types preserved
function search(query: string, page: number): void {
  console.log(`Searching: ${query} page ${page}`);
}

const debouncedSearch = debounce(search, 300);
debouncedSearch('typescript', 1); // OK
debouncedSearch(42, 'wrong');     // Error: Argument of type 'number' is not assignable to 'string'

const throttledSearch = throttle(search, 1000);
throttledSearch('node', 2); // OK, typed correctly
```

A type-safe `groupBy` utility leveraging TypeScript generics, plus the new `Object.groupBy` from ES2024.

```typescript
// Custom groupBy with full type safety
function groupBy<T, K extends string | number>(
  items: T[],
  keyFn: (item: T) => K
): Record<K, T[]> {
  const result = {} as Record<K, T[]>;
  for (const item of items) {
    const key = keyFn(item);
    (result[key] ??= []).push(item);
  }
  return result;
}

// Usage
interface Order {
  id: string;
  status: 'pending' | 'shipped' | 'delivered';
  amount: number;
}

const orders: Order[] = [
  { id: '1', status: 'pending', amount: 100 },
  { id: '2', status: 'shipped', amount: 200 },
  { id: '3', status: 'pending', amount: 150 },
];

const byStatus = groupBy(orders, o => o.status);
// Record<'pending' | 'shipped' | 'delivered', Order[]>
byStatus.pending;  // Order[]
byStatus.shipped;  // Order[]

// ES2024 Object.groupBy (Node.js 21+, TypeScript 5.4+)
// Requires: lib: ["es2024"] or lib: ["esnext"] in tsconfig
const grouped = Object.groupBy(orders, o => o.status);
// Partial<Record<'pending' | 'shipped' | 'delivered', Order[]>>
// Note: returns Partial because some keys may have no items

// Map.groupBy for non-string keys
const byAmount = Map.groupBy(orders, o => o.amount > 150 ? 'high' : 'low');
// Map<'high' | 'low', Order[]>
```

`Object.groupBy` returns `Partial<Record<K, T[]>>` because not all keys necessarily appear in the data. Use the custom version for `Record<K, T[]>` when you know all keys are present.

Create reusable type guard factories for common patterns like nullable checks, instance checks, and property checks.

```typescript
// Guard factories
function isInstanceOf<T>(ctor: new (...args: any[]) => T) {
  return (value: unknown): value is T => value instanceof ctor;
}

function hasProperty<K extends string>(key: K) {
  return <T extends Record<K, unknown>>(value: unknown): value is T =>
    typeof value === 'object' && value !== null && key in value;
}

function isOneOf<T extends readonly unknown[]>(...values: T) {
  return (value: unknown): value is T[number] => values.includes(value);
}

function isArrayOf<T>(guard: (v: unknown) => v is T) {
  return (value: unknown): value is T[] =>
    Array.isArray(value) && value.every(guard);
}

function isNonNull<T>(value: T): value is NonNullable<T> {
  return value !== null && value !== undefined;
}

// Usage
const isError = isInstanceOf(Error);
const isTypedError = isInstanceOf(TypeError);
const isString = (v: unknown): v is string => typeof v === 'string';
const isStringArray = isArrayOf(isString);
const isStatus = isOneOf('active', 'inactive', 'pending');
const hasId = hasProperty('id');

// In practice
const values: unknown[] = [1, 'hello', null, new Error('fail')];

const errors = values.filter(isError);     // Error[]
const strings = values.filter(isString);   // string[]
const nonNull = values.filter(isNonNull);  // (string | number | Error)[]

// Composing guards
function isUser(value: unknown): value is { id: string; name: string } {
  return hasId(value) && hasProperty('name')(value)
    && typeof (value as any).id === 'string'
    && typeof (value as any).name === 'string';
}
```

Fine-grained utility types for making specific properties required or optional without affecting the rest.

```typescript
// Make specific keys required, rest unchanged
type RequireKeys<T, K extends keyof T> = Omit<T, K> & Required<Pick<T, K>>;

// Make specific keys optional, rest unchanged
type OptionalKeys<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;

// Make specific keys nullable
type NullableKeys<T, K extends keyof T> = Omit<T, K> & { [P in K]: T[P] | null };

// Make all keys except specified ones optional
type OnlyRequired<T, K extends keyof T> = Partial<T> & Required<Pick<T, K>>;

// Override specific key types
type Override<T, U extends Partial<Record<keyof T, unknown>>> = Omit<T, keyof U> & U;

// Usage examples
interface User {
  id: string;
  name: string;
  email?: string;
  avatar?: string;
  bio?: string;
}

// Registration form: name and email required, rest optional
type RegistrationForm = RequireKeys<User, 'name' | 'email'>;
// { id: string; name: string; email: string; avatar?: string; bio?: string }

// Profile update: only id required
type ProfileUpdate = OnlyRequired<User, 'id'>;
// { id: string; name?: string; email?: string; avatar?: string; bio?: string }

// API response: override id type
type UserResponse = Override<User, { id: number; createdAt: Date }>;
// { id: number; name: string; email?: string; avatar?: string; bio?: string; createdAt: Date }

// Soft-delete: make nullable
type SoftDeleteUser = NullableKeys<User, 'name' | 'email'>;
// { id: string; name: string | null; email: string | null | undefined; avatar?: string; bio?: string }
```

These utilities compose well together: `RequireKeys<OptionalKeys<User, 'bio'>, 'email'>` makes bio optional and email required.

Process an array of items with a concurrency limit, preserving TypeScript types.

```typescript
async function asyncPool<T, R>(
  items: T[],
  concurrency: number,
  fn: (item: T, index: number) => Promise<R>
): Promise<R[]> {
  const results: R[] = new Array(items.length);
  let nextIndex = 0;

  async function worker() {
    while (nextIndex < items.length) {
      const index = nextIndex++;
      results[index] = await fn(items[index], index);
    }
  }

  const workers = Array.from(
    { length: Math.min(concurrency, items.length) },
    () => worker()
  );

  await Promise.all(workers);
  return results;
}

// Usage: process 100 URLs with max 5 concurrent requests
const urls = Array.from({ length: 100 }, (_, i) => `https://api.example.com/item/${i}`);

interface Item { id: number; name: string }

const items = await asyncPool<string, Item>(urls, 5, async (url, index) => {
  const response = await fetch(url);
  if (!response.ok) throw new Error(`Failed: ${url}`);
  return response.json() as Promise<Item>;
});
// items: Item[] — ordered, same index as input URLs

// With error handling per item
const results = await asyncPool(urls, 5, async (url) => {
  try {
    const res = await fetch(url);
    return { ok: true as const, data: await res.json() as Item };
  } catch (error) {
    return { ok: false as const, error: String(error) };
  }
});
// results: ({ ok: true; data: Item } | { ok: false; error: string })[]
```

The pool maintains exactly N concurrent workers. Results are ordered by input index, not completion order.

Combine `as const satisfies` with a validation function for configs that are type-checked at compile time and validated at runtime.

```typescript
import { z } from 'zod';

// Define schema
const featureFlagSchema = z.object({
  name: z.string(),
  enabled: z.boolean(),
  rolloutPercent: z.number().min(0).max(100),
  allowedUsers: z.array(z.string()).optional(),
});

type FeatureFlag = z.infer<typeof featureFlagSchema>;

// Type-safe config with literal types preserved
const featureFlags = [
  {
    name: 'dark-mode',
    enabled: true,
    rolloutPercent: 100,
  },
  {
    name: 'new-dashboard',
    enabled: true,
    rolloutPercent: 25,
    allowedUsers: ['admin-1', 'admin-2'],
  },
  {
    name: 'ai-suggestions',
    enabled: false,
    rolloutPercent: 0,
  },
] as const satisfies readonly FeatureFlag[];

// Derive flag names as a union type
type FlagName = typeof featureFlags[number]['name'];
// 'dark-mode' | 'new-dashboard' | 'ai-suggestions'

// Type-safe flag lookup
function getFlag(name: FlagName): FeatureFlag {
  const flag = featureFlags.find(f => f.name === name);
  if (!flag) throw new Error(`Unknown flag: ${name}`);
  return flag;
}

getFlag('dark-mode');     // OK
getFlag('nonexistent');   // Error: Argument not assignable to FlagName

// Runtime validation (e.g., from API)
function validateFlags(raw: unknown): FeatureFlag[] {
  return z.array(featureFlagSchema).parse(raw);
}
```
